SET NOCOUNT ON;
UPDATE [AspNetUsers] SET [AccessFailedCount] = @p0, [AvatarUrl] = @p1, [ConcurrencyStamp] = @p2, [DateOfBirth] = @p3, [Email] = @p4, [EmailConfirmed] = @p5, [FirstName] = @p6, [IsDeleted] = @p7, [JobTitle] = @p8, [LockoutEnabled] = @p9, [LockoutEnd] = @p10, [NormalizedEmail] = @p11, [NormalizedUserName] = @p12, [PasswordHash] = @p13, [PhoneNumber] = @p14, [PhoneNumberConfirmed] = @p15, [SecondName] = @p16, [SecurityStamp] = @p17, [SubscriptionType] = @p18, [TwoFactorEnabled] = @p19, [UserName] = @p20
OUTPUT 1
WHERE [Id] = @p21 AND [ConcurrencyStamp] = @p22;
INSERT INTO [RefreshTokens] ([UserId], [CreatedAt], [ExpiredAt], [RevokedAt], [refreshToken])
OUTPUT INSERTED.[Id]
VALUES (@p23, @p24, @p25, @p26, @p27);

